// ============================================
// Market Data Collector v5.1 - LuxAlgo Style
// + Squeeze Percentage (like LuxAlgo 10.64%)
// + Composite Trend Score System (-100 to +100)
// ============================================

const SYMBOL = 'BTCUSDT';

async function fetchBinance(endpoint) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://fapi.binance.com${endpoint}`,
      json: true
    });
    return response;
  } catch (e) {
    console.log('Error fetching ' + endpoint + ':', e.message);
    return null;
  }
}

const [
  klines5m, klines15m, klines1h, klines4h, klines1d,
  funding, ticker, openInterest, openInterestHist,
  longShort5m, topTrader5m,
  longShort15m, topTrader15m,
  longShort1h, topTrader1h,
  longShort4h, topTrader4h
] = await Promise.all([
  fetchBinance.call(this, `/fapi/v1/klines?symbol=${SYMBOL}&interval=5m&limit=50`),
  fetchBinance.call(this, `/fapi/v1/klines?symbol=${SYMBOL}&interval=15m&limit=50`),
  fetchBinance.call(this, `/fapi/v1/klines?symbol=${SYMBOL}&interval=1h&limit=50`),
  fetchBinance.call(this, `/fapi/v1/klines?symbol=${SYMBOL}&interval=4h&limit=50`),
  fetchBinance.call(this, `/fapi/v1/klines?symbol=${SYMBOL}&interval=1d&limit=30`),
  fetchBinance.call(this, `/fapi/v1/premiumIndex?symbol=${SYMBOL}`),
  fetchBinance.call(this, `/fapi/v1/ticker/24hr?symbol=${SYMBOL}`),
  fetchBinance.call(this, `/fapi/v1/openInterest?symbol=${SYMBOL}`),
  fetchBinance.call(this, `/futures/data/openInterestHist?symbol=${SYMBOL}&period=1h&limit=25`),
  fetchBinance.call(this, `/futures/data/globalLongShortAccountRatio?symbol=${SYMBOL}&period=5m&limit=1`),
  fetchBinance.call(this, `/futures/data/topLongShortPositionRatio?symbol=${SYMBOL}&period=5m&limit=1`),
  fetchBinance.call(this, `/futures/data/globalLongShortAccountRatio?symbol=${SYMBOL}&period=15m&limit=1`),
  fetchBinance.call(this, `/futures/data/topLongShortPositionRatio?symbol=${SYMBOL}&period=15m&limit=1`),
  fetchBinance.call(this, `/futures/data/globalLongShortAccountRatio?symbol=${SYMBOL}&period=1h&limit=1`),
  fetchBinance.call(this, `/futures/data/topLongShortPositionRatio?symbol=${SYMBOL}&period=1h&limit=1`),
  fetchBinance.call(this, `/futures/data/globalLongShortAccountRatio?symbol=${SYMBOL}&period=4h&limit=1`),
  fetchBinance.call(this, `/futures/data/topLongShortPositionRatio?symbol=${SYMBOL}&period=4h&limit=1`)
]);

function parseKlines(klines) {
  if (!klines || !Array.isArray(klines) || klines.length === 0) {
    return { opens: [0], highs: [0], lows: [0], closes: [0], volumes: [0], timestamps: [Date.now()] };
  }
  return {
    opens: klines.map(k => parseFloat(k[1])),
    highs: klines.map(k => parseFloat(k[2])),
    lows: klines.map(k => parseFloat(k[3])),
    closes: klines.map(k => parseFloat(k[4])),
    volumes: klines.map(k => parseFloat(k[5])),
    timestamps: klines.map(k => k[0])
  };
}

function getLSRatio(data) {
  if (data && Array.isArray(data) && data.length > 0) return parseFloat(data[0].longShortRatio) || 1.0;
  return 1.0;
}

function calculateEMA(prices, period) {
  if (prices.length === 0) return 0;
  const k = 2 / (period + 1);
  let ema = prices[0];
  for (let i = 1; i < prices.length; i++) ema = prices[i] * k + ema * (1 - k);
  return ema;
}

function calculateSMA(prices, period) {
  if (prices.length < period) return prices[prices.length - 1] || 0;
  return prices.slice(-period).reduce((a, b) => a + b, 0) / period;
}

function calculateRSI(prices, period = 14) {
  if (prices.length < period + 1) return 50;
  let gains = 0, losses = 0;
  for (let i = 1; i <= period; i++) {
    const diff = prices[i] - prices[i - 1];
    if (diff >= 0) gains += diff; else losses -= diff;
  }
  let avgGain = gains / period, avgLoss = losses / period;
  for (let i = period + 1; i < prices.length; i++) {
    const diff = prices[i] - prices[i - 1];
    avgGain = (avgGain * (period - 1) + (diff > 0 ? diff : 0)) / period;
    avgLoss = (avgLoss * (period - 1) + (diff < 0 ? -diff : 0)) / period;
  }
  if (avgLoss === 0) return 100;
  return 100 - (100 / (1 + avgGain / avgLoss));
}

function calculateATR(highs, lows, closes, period = 14) {
  if (highs.length < period + 1) return 0;
  const trs = [];
  for (let i = 1; i < highs.length; i++) {
    trs.push(Math.max(highs[i] - lows[i], Math.abs(highs[i] - closes[i-1]), Math.abs(lows[i] - closes[i-1])));
  }
  return trs.slice(-period).reduce((a, b) => a + b, 0) / period;
}

function calculateMACD(prices) {
  const ema12 = calculateEMA(prices, 12), ema26 = calculateEMA(prices, 26);
  const macd = ema12 - ema26, signal = calculateEMA(prices.slice(-9), 9);
  return { macd, signal, histogram: macd - signal };
}

function calculateBB(prices, period = 20, stdDev = 2) {
  const sma = calculateSMA(prices, period), slice = prices.slice(-period);
  if (slice.length === 0) return { upper: 0, middle: 0, lower: 0 };
  const variance = slice.reduce((sum, p) => sum + Math.pow(p - sma, 2), 0) / period;
  const std = Math.sqrt(variance);
  return { upper: sma + (stdDev * std), middle: sma, lower: sma - (stdDev * std) };
}

function calculateOBV(closes, volumes) {
  if (closes.length < 2) return 0;
  let obv = 0;
  for (let i = 1; i < closes.length; i++) {
    if (closes[i] > closes[i-1]) obv += volumes[i];
    else if (closes[i] < closes[i-1]) obv -= volumes[i];
  }
  return obv;
}

function calculateADX(highs, lows, closes, period = 14) {
  if (highs.length < period + 1) return { adx: 25 };
  const trs = [], plusDMs = [], minusDMs = [];
  for (let i = 1; i < highs.length; i++) {
    trs.push(Math.max(highs[i] - lows[i], Math.abs(highs[i] - closes[i-1]), Math.abs(lows[i] - closes[i-1])));
    const upMove = highs[i] - highs[i-1], downMove = lows[i-1] - lows[i];
    plusDMs.push(upMove > downMove && upMove > 0 ? upMove : 0);
    minusDMs.push(downMove > upMove && downMove > 0 ? downMove : 0);
  }
  let atr = trs.slice(0, period).reduce((a,b) => a+b, 0);
  let plusDM = plusDMs.slice(0, period).reduce((a,b) => a+b, 0);
  let minusDM = minusDMs.slice(0, period).reduce((a,b) => a+b, 0);
  const dxValues = [];
  for (let i = period; i < trs.length; i++) {
    atr = atr - (atr / period) + trs[i];
    plusDM = plusDM - (plusDM / period) + plusDMs[i];
    minusDM = minusDM - (minusDM / period) + minusDMs[i];
    const plusDI = (plusDM / atr) * 100, minusDI = (minusDM / atr) * 100;
    const dx = Math.abs(plusDI - minusDI) / (plusDI + minusDI) * 100;
    if (!isNaN(dx)) dxValues.push(dx);
  }
  const adx = dxValues.length > 0 ? dxValues.slice(-period).reduce((a,b) => a+b, 0) / Math.min(dxValues.length, period) : 25;
  return { adx: Math.round(adx * 100) / 100 };
}

// UPDATED: Squeeze with Percentage (LuxAlgo style)
function calculateSqueeze(highs, lows, closes, period = 20) {
  if (closes.length < period) return { squeezeOn: false, squeezePct: 0 };
  const bb = calculateBB(closes, period, 2);
  const bbWidth = bb.upper - bb.lower;
  const atr = calculateATR(highs, lows, closes, period);
  const kcWidth = atr * 1.5 * 2;

  // Squeeze ON when BB is inside KC
  const squeezeOn = bbWidth < kcWidth;

  // Squeeze Percentage: How much BB is compressed relative to KC
  // Higher % = more compression = bigger move coming
  // Formula: (1 - BB_width/KC_width) * 100
  let squeezePct = 0;
  if (kcWidth > 0) {
    squeezePct = Math.max(0, (1 - bbWidth / kcWidth) * 100);
    squeezePct = Math.round(squeezePct * 100) / 100;
  }

  return { squeezeOn, squeezePct };
}

function calculateVolumeSentiment(opens, closes, volumes, period = 14) {
  if (closes.length < period) return 0;
  let buyVolume = 0, sellVolume = 0;
  for (let i = closes.length - period; i < closes.length; i++) {
    if (closes[i] >= opens[i]) buyVolume += volumes[i]; else sellVolume += volumes[i];
  }
  const total = buyVolume + sellVolume;
  if (total === 0) return 0;
  return Math.round(((buyVolume - sellVolume) / total) * 100 * 100) / 100;
}

function calculateSuperTrend(highs, lows, closes, period = 10, multiplier = 3) {
  if (closes.length < period) return { value: closes[closes.length-1], direction: 'NEUTRAL' };
  const atr = calculateATR(highs, lows, closes, period);
  const current = closes[closes.length - 1], high = highs[highs.length - 1], low = lows[lows.length - 1];
  const basicLowerBand = ((high + low) / 2) - (multiplier * atr);
  const basicUpperBand = ((high + low) / 2) + (multiplier * atr);
  if (current > basicLowerBand) return { value: Math.round(basicLowerBand * 100) / 100, direction: 'UP' };
  return { value: Math.round(basicUpperBand * 100) / 100, direction: 'DOWN' };
}

// LuxAlgo Style Composite Trend Score (-100 to +100)
function calculateTrendScore(indicators) {
  const { closes, ema20, ema50, rsi, macd, macdSignal, adx, squeezeOn, volumeSentiment, supertrendDirection } = indicators;

  if (closes.length === 0) return { score: 0, trend: 'NEUTRAL', confidence: 'LOW' };

  const current = closes[closes.length - 1];
  let score = 0;
  const signals = [];

  // 1. Price vs EMA20 (±15)
  if (current > ema20 * 1.001) { score += 15; signals.push('BULL'); }
  else if (current < ema20 * 0.999) { score -= 15; signals.push('BEAR'); }
  else { signals.push('NEUTRAL'); }

  // 2. EMA20 vs EMA50 (±15)
  if (ema20 > ema50 * 1.001) { score += 15; signals.push('BULL'); }
  else if (ema20 < ema50 * 0.999) { score -= 15; signals.push('BEAR'); }
  else { signals.push('NEUTRAL'); }

  // 3. RSI (±20)
  if (rsi > 60) { score += 20; signals.push('BULL'); }
  else if (rsi > 55) { score += 10; signals.push('BULL'); }
  else if (rsi < 40) { score -= 20; signals.push('BEAR'); }
  else if (rsi < 45) { score -= 10; signals.push('BEAR'); }
  else { signals.push('NEUTRAL'); }

  // 4. MACD vs Signal (±15)
  if (macd > macdSignal) { score += 15; signals.push('BULL'); }
  else if (macd < macdSignal) { score -= 15; signals.push('BEAR'); }
  else { signals.push('NEUTRAL'); }

  // 5. Volume Sentiment (±20)
  if (volumeSentiment > 30) { score += 20; signals.push('BULL'); }
  else if (volumeSentiment > 15) { score += 10; signals.push('BULL'); }
  else if (volumeSentiment < -30) { score -= 20; signals.push('BEAR'); }
  else if (volumeSentiment < -15) { score -= 10; signals.push('BEAR'); }
  else { signals.push('NEUTRAL'); }

  // 6. SuperTrend (±15)
  if (supertrendDirection === 'UP') { score += 15; signals.push('BULL'); }
  else if (supertrendDirection === 'DOWN') { score -= 15; signals.push('BEAR'); }
  else { signals.push('NEUTRAL'); }

  // ADX-based confidence
  let confidence = 'LOW', adxMultiplier = 0.5;
  if (adx >= 30) { confidence = 'HIGH'; adxMultiplier = 1.0; }
  else if (adx >= 20) { confidence = 'MEDIUM'; adxMultiplier = 0.75; }

  if (squeezeOn) { confidence = 'LOW'; adxMultiplier = 0.3; }

  const adjustedScore = Math.round(score * adxMultiplier);

  let trend = 'NEUTRAL';
  if (adjustedScore >= 40) trend = 'BULLISH';
  else if (adjustedScore >= 20) trend = 'WEAK_BULLISH';
  else if (adjustedScore <= -40) trend = 'BEARISH';
  else if (adjustedScore <= -20) trend = 'WEAK_BEARISH';

  if (squeezeOn || adx < 15) trend = 'NEUTRAL';

  return { score: adjustedScore, rawScore: score, trend, confidence };
}

function getTrendFromScore(trendData) {
  const { trend } = trendData;
  if (trend === 'BULLISH' || trend === 'WEAK_BULLISH') return 'BULLISH';
  if (trend === 'BEARISH' || trend === 'WEAK_BEARISH') return 'BEARISH';
  return 'NEUTRAL';
}

function detectMarketState(adx, squeezeOn, trend) {
  if (squeezeOn) return 'SQUEEZE';
  if (adx < 20) return 'RANGING';
  if (adx >= 25) {
    if (trend === 'BULLISH') return 'TRENDING_UP';
    if (trend === 'BEARISH') return 'TRENDING_DOWN';
  }
  return 'WEAK_TREND';
}

function calculateComplete(data) {
  const { opens, highs, lows, closes, volumes } = data;
  const idx = Math.max(0, closes.length - 1);
  const rsi = calculateRSI(closes), macd = calculateMACD(closes);
  const ema20 = calculateEMA(closes, 20), ema50 = calculateEMA(closes, 50);
  const atr = calculateATR(highs, lows, closes), bb = calculateBB(closes), obv = calculateOBV(closes, volumes);
  const adxData = calculateADX(highs, lows, closes);
  const squeeze = calculateSqueeze(highs, lows, closes); // Now returns squeezePct
  const volSentiment = calculateVolumeSentiment(opens, closes, volumes);
  const supertrend = calculateSuperTrend(highs, lows, closes);

  const trendScore = calculateTrendScore({
    closes, ema20, ema50, rsi, 
    macd: macd.macd, macdSignal: macd.signal,
    adx: adxData.adx, squeezeOn: squeeze.squeezeOn,
    volumeSentiment: volSentiment, supertrendDirection: supertrend.direction
  });

  const trend = getTrendFromScore(trendScore);
  const marketState = detectMarketState(adxData.adx, squeeze.squeezeOn, trend);

  return {
    close: closes[idx], rsi: Math.round(rsi * 100) / 100, macd: Math.round(macd.macd * 100) / 100,
    macdSignal: Math.round(macd.signal * 100) / 100, macdHistogram: Math.round(macd.histogram * 100) / 100,
    ema20: Math.round(ema20 * 100) / 100, ema50: Math.round(ema50 * 100) / 100, atr: Math.round(atr * 100) / 100,
    bbUpper: Math.round(bb.upper * 100) / 100, bbMiddle: Math.round(bb.middle * 100) / 100, bbLower: Math.round(bb.lower * 100) / 100,
    obv: Math.round(obv), adx: adxData.adx, 
    squeezeOn: squeeze.squeezeOn, squeezePct: squeeze.squeezePct, // NEW: squeezePct
    volumeSentiment: volSentiment,
    supertrend: supertrend.value, supertrendDirection: supertrend.direction, 
    trend, marketState,
    trendScore: trendScore.score, trendConfidence: trendScore.confidence
  };
}

const data5m = parseKlines(klines5m), data15m = parseKlines(klines15m), data1h = parseKlines(klines1h), data4h = parseKlines(klines4h), data1d = parseKlines(klines1d);
const ind5m = calculateComplete(data5m), ind15m = calculateComplete(data15m), ind1h = calculateComplete(data1h), ind4h = calculateComplete(data4h), ind1d = calculateComplete(data1d);

const ls5m = getLSRatio(longShort5m), topLs5m = getLSRatio(topTrader5m);
const ls15m = getLSRatio(longShort15m), topLs15m = getLSRatio(topTrader15m);
const ls1h = getLSRatio(longShort1h), topLs1h = getLSRatio(topTrader1h);
const ls4h = getLSRatio(longShort4h), topLs4h = getLSRatio(topTrader4h);

let oiChange = 0, currentOI = openInterest ? parseFloat(openInterest.openInterest) || 0 : 0;
if (openInterestHist && Array.isArray(openInterestHist) && openInterestHist.length >= 25) {
  const curr = parseFloat(openInterestHist[openInterestHist.length - 1].sumOpenInterest) || 0;
  const prev = parseFloat(openInterestHist[0].sumOpenInterest) || 0;
  if (prev > 0) oiChange = ((curr - prev) / prev) * 100;
}
let oiChange1h = 0;
if (openInterestHist && Array.isArray(openInterestHist) && openInterestHist.length >= 2) {
  const recent = parseFloat(openInterestHist[openInterestHist.length - 1].sumOpenInterest) || 0;
  const prev = parseFloat(openInterestHist[openInterestHist.length - 2].sumOpenInterest) || 0;
  if (prev > 0) oiChange1h = ((recent - prev) / prev) * 100;
}
let volChange24h = 0;
if (data1h.volumes.length >= 48) {
  const recent = data1h.volumes.slice(-24).reduce((a,b) => a+b, 0);
  const prev = data1h.volumes.slice(-48, -24).reduce((a,b) => a+b, 0);
  if (prev > 0) volChange24h = ((recent - prev) / prev) * 100;
}

const idx5m = Math.max(0, data5m.closes.length - 1);

return [{ json: {
  symbol: 'BTCUSD', timeframe: '5m',
  // 5M + Squeeze Pct
  open_price: data5m.opens[idx5m], high_price: data5m.highs[idx5m], low_price: data5m.lows[idx5m], close_price: data5m.closes[idx5m], volume: data5m.volumes[idx5m],
  rsi: ind5m.rsi, macd: ind5m.macd, macd_signal: ind5m.macdSignal, macd_histogram: ind5m.macdHistogram,
  atr: ind5m.atr, ema_20: ind5m.ema20, ema_50: ind5m.ema50, bb_upper: ind5m.bbUpper, bb_middle: ind5m.bbMiddle, bb_lower: ind5m.bbLower, obv: ind5m.obv,
  adx: ind5m.adx, squeeze_on: ind5m.squeezeOn, squeeze_pct: ind5m.squeezePct,
  volume_sentiment: ind5m.volumeSentiment, supertrend: ind5m.supertrend, supertrend_direction: ind5m.supertrendDirection,
  market_state: ind5m.marketState, trend_strength_pct: ind5m.adx, long_short_ratio: ls5m, top_trader_ls_ratio: topLs5m,
  // 15M + Squeeze Pct
  close_15m: ind15m.close, rsi_15m: ind15m.rsi, macd_15m: ind15m.macd, trend_15m: ind15m.trend, obv_15m: ind15m.obv,
  adx_15m: ind15m.adx, squeeze_15m: ind15m.squeezeOn, squeeze_pct_15m: ind15m.squeezePct,
  volume_sentiment_15m: ind15m.volumeSentiment,
  supertrend_15m: ind15m.supertrend, supertrend_direction_15m: ind15m.supertrendDirection,
  ema_20_15m: ind15m.ema20, ema_50_15m: ind15m.ema50, atr_15m: ind15m.atr,
  bb_upper_15m: ind15m.bbUpper, bb_middle_15m: ind15m.bbMiddle, bb_lower_15m: ind15m.bbLower,
  long_short_ratio_15m: ls15m, top_trader_ls_ratio_15m: topLs15m,
  trend_score_15m: ind15m.trendScore,
  // 1H + Squeeze Pct
  close_1h: ind1h.close, rsi_1h: ind1h.rsi, macd_1h: ind1h.macd, trend_1h: ind1h.trend, obv_1h: ind1h.obv,
  adx_1h: ind1h.adx, squeeze_1h: ind1h.squeezeOn, squeeze_pct_1h: ind1h.squeezePct,
  volume_sentiment_1h: ind1h.volumeSentiment,
  supertrend_1h: ind1h.supertrend, supertrend_direction_1h: ind1h.supertrendDirection,
  ema_20_1h: ind1h.ema20, ema_50_1h: ind1h.ema50, atr_1h: ind1h.atr,
  long_short_ratio_1h: ls1h, top_trader_ls_ratio_1h: topLs1h, oi_change_1h: Math.round(oiChange1h * 100) / 100,
  trend_score_1h: ind1h.trendScore,
  // 4H
  close_4h: ind4h.close, rsi_4h: ind4h.rsi, macd_4h: ind4h.macd, trend_4h: ind4h.trend, adx_4h: ind4h.adx,
  long_short_ratio_4h: ls4h, top_trader_ls_ratio_4h: topLs4h,
  trend_score_4h: ind4h.trendScore,
  // Daily
  close_1d: ind1d.close, rsi_1d: ind1d.rsi, macd_1d: ind1d.macd, trend_1d: ind1d.trend, obv_1d: ind1d.obv,
  // Global
  funding_rate: funding ? parseFloat(funding.lastFundingRate) || 0 : 0, open_interest: currentOI, open_interest_change: Math.round(oiChange * 100) / 100,
  price_change_24h: ticker ? parseFloat(ticker.priceChangePercent) || 0 : 0, volume_24h: ticker ? parseFloat(ticker.volume) || 0 : 0, volume_change_24h: Math.round(volChange24h * 100) / 100,
  trend_confidence: ind15m.trendConfidence,
  timestamp: new Date(data5m.timestamps[idx5m]).toISOString()
}}];
